#include <stdio.h>

int main() {
    int t, s, q;
    scanf("%d %d %d", &t, &s, &q);
    int r = 1;
    while (t > s * q) {
        s *= q;
        r += 1;
    }
    printf("%d", r);
    return 0;
}
